import { useEffect, useState } from "react";

import "./App.css";
import SearchIcon from "./search.svg";

import MovieCard from "./MovieCard";

const API_URL = "http://www.omdbapi.com?apikey=3782fe82";
const TRENDING_MOVIES = ["tt0816692", "tt12361974", "tt3152592"]; // IMDb IDs of trending movies

const App = () => {
  const [movies, setMovies] = useState([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [currentPage, setCurrentPage] = useState(1);
  const [totalResults, setTotalResults] = useState(0);

  const searchMovies = async (title, page = 1) => {
    const response = await fetch(`${API_URL}&s=${title}&page=${page}`);
    const data = await response.json();

    setMovies(data.Search || []);
    setTotalResults(parseInt(data.totalResults));
  };

  const fetchTrendingMovies = async () => {
    const promises = TRENDING_MOVIES.map(async (imdbID) => {
      const response = await fetch(`${API_URL}&i=${imdbID}`);
      const data = await response.json();
      return data;
    });
    const trendingMovies = await Promise.all(promises);
    setMovies(trendingMovies);
  };

  useEffect(() => {
    // Fetch trending movies on initial load
    fetchTrendingMovies();

    // Fetch movies based on the search term and current page
    if (searchTerm) {
      searchMovies(searchTerm, currentPage);
    }
  }, [searchTerm, currentPage]); // Include searchTerm and currentPage in the dependency array

  const handleSearch = () => {
    setCurrentPage(1);
    searchMovies(searchTerm, 1);
  };

  const handlePagination = (page) => {
    setCurrentPage(page);
  };

  const totalPages = Math.ceil(totalResults / 10);

  return (
    <div className="app">
      <h1>MovieFox</h1>

      <div className="search">
        <input
          placeholder="Enter Movie Name"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === "Enter") handleSearch();
          }}
        />
        <img
          src={SearchIcon}
          alt="search"
          onClick={handleSearch}
        />
      </div>

      {movies.length > 0 ? (
        <div className="container">
          {movies.map((movie) => (
            <MovieCard key={movie.imdbID} movie={movie} />
          ))}
        </div>
      ) : (
        <div className="trending">
          <h2>Trending Movies</h2>
          {/* Render trending movie images or components */}
        </div>
      )}

      {totalPages > 1 && (
        <div className="pagination">
          <button
            onClick={() => handlePagination(currentPage - 1)}
            disabled={currentPage === 1}
          >
            Previous
          </button>
          <span>{`${currentPage} / ${totalPages}`}</span>
          <button
            onClick={() => handlePagination(currentPage + 1)}
            disabled={currentPage === totalPages}
          >
            Next
          </button>
        </div>
      )}
    </div>
  );
};

export default App;
